//B. Omkar and Last Class of Math #include <bits/stdc++.h>using namespace std;#define int long long int void fast_io() {    std::ios_base::sync_with_stdio(false);    std::cin.tie(NULL);    std::cout.tie(NULL);} signed main() {    fast_io();    int t;    cin>>t;    while(t--){        int n;        cin>>n;        int a=0;        if(n%2==0){            cout<<n/2<<" "<<n/2<<endl;        }                else{            for(int i=2;i*i<=n;i++){                if(n%i==0){                    a=1;                    break;                }            }            if(a==0){                cout<<1<<" "<<n-1<<endl;            }            if(a==1){                int z=0;                for(int i=3;i*i<=n;i++){                    if(n%i==0){                        z=max(z,n/i);                    }                }                cout<<z<<" "<<n-z<<endl;;            }        }    }    return 0;}